import { useCallback } from 'react';

import { needsScrollbarFix } from '../utils/needs-scrollbar-fix.js';

/**
 * Hook to detect if a scrollbar is present and set CSS custom property to avoid rerenders
 * @returns refCallback - ref callback to attach to element
 */
export const useScrollbarDetection = () => {
  const checkScrollbar = useCallback((element: HTMLElement) => {
    const hasVerticalScrollbar = element.scrollHeight > element.clientHeight;
    const needsFix = hasVerticalScrollbar && needsScrollbarFix();

    element.style.setProperty('--needs-scrollbar-fix', needsFix ? '1' : '0');
  }, []);

  const refCallback = useCallback(
    (element: HTMLElement | null) => {
      if (!element) {
        return;
      }

      checkScrollbar(element);
    },
    [checkScrollbar],
  );

  return refCallback;
};
